+func (t *localPerfTracker) syncAnimatedTPSHistory() {
+	if t == nil || t.springs == nil {
+		return
+	}
+
+	for i, value := range t.TPSHistory {
+		key := fmt.Sprintf("tps:%d", i)
+		if !t.springs.Has(key) {
+			t.springs.SetImmediate(key, value)
+			continue
